export const DIRECTION_IMAGES = {
  s: {
    'up.png': 'data:image/png;base64,',
    'topright.png': 'data:image/png;base64,',
    'right.png': 'data:image/png;base64,',
    'downright.png': 'data:image/png;base64,',
    'down.png': 'data:image/png;base64,',
    'downleft.png': 'data:image/png;base64,',
    'left.png': 'data:image/png;base64,',
    'topleft.png': 'data:image/png;base64,',
  },
  p: {
    'up.png': 'data:image/png;base64,',
    'topright.png': 'data:image/png;base64,',
    'right.png': 'data:image/png;base64,',
    'downright.png': 'data:image/png;base64,',
    'down.png': 'data:image/png;base64,',
    'downleft.png': 'data:image/png;base64,',
    'left.png': 'data:image/png;base64,',
    'topleft.png': 'data:image/png;base64,',
  },
  c: {
    'up.png': 'data:image/png;base64,',
    'topright.png': 'data:image/png;base64,',
    'right.png': 'data:image/png;base64,',
    'downright.png': 'data:image/png;base64,',
    'down.png': 'data:image/png;base64,',
    'downleft.png': 'data:image/png;base64,',
    'left.png': 'data:image/png;base64,',
    'topleft.png': 'data:image/png;base64,',
  },
} as const;

export type VehiclePinType = 's' | 'p' | 'c';
export type DirectionImageName = keyof typeof DIRECTION_IMAGES.s;

export interface DirectionImageData {
  name: DirectionImageName;
  size: [number, number];
  anchor: [number, number];
}

export const getDirectionImageData = (angle: number): DirectionImageData => {
  if (angle >= 0 && angle <= 22.5) {
    return { name: 'up.png', size: [30, 40], anchor: [15, 20] };
  }
  if (angle > 22.5 && angle <= 67.5) {
    return { name: 'topright.png', size: [55, 50], anchor: [27, 25] };
  }
  if (angle > 67.5 && angle <= 112.5) {
    return { name: 'right.png', size: [55, 50], anchor: [27, 25] };
  }
  if (angle > 112.5 && angle <= 157.5) {
    return { name: 'downright.png', size: [55, 50], anchor: [27, 25] };
  }
  if (angle > 157.5 && angle <= 202.5) {
    return { name: 'down.png', size: [30, 40], anchor: [15, 20] };
  }
  if (angle > 202.5 && angle <= 247.5) {
    return { name: 'downleft.png', size: [55, 50], anchor: [27, 25] };
  }
  if (angle > 247.5 && angle <= 292.5) {
    return { name: 'left.png', size: [55, 50], anchor: [27, 25] };
  }
  if (angle > 292.5 && angle <= 337.5) {
    return { name: 'topleft.png', size: [55, 50], anchor: [27, 25] };
  }
  return { name: 'up.png', size: [30, 40], anchor: [15, 20] };
};

const getDirectionImageName = (angle: number): DirectionImageName => {
  return getDirectionImageData(angle).name;
};

export const getDirectionImage = (angle: number, pinType: VehiclePinType = 's') => {
  const imageName = getDirectionImageName(angle);
  return { uri: DIRECTION_IMAGES[pinType][imageName] };
};
